qry:select.qry:xquery:
				for $r in SQL('
					SELECT
						REQ.oi_req,
						REQ.c_req,
						REQ.d_req,
						REQ.f_req					                                                                       
					FROM
						SEL02_REQ AS REQ
					WHERE 
						REQ.oi_empresa = {#SOURCE:@oi_empresa} 
						{%? (#FILTRO:@f_desde!='')           
						{% AND REQ.f_req >= {#FILTRO:@f_desde} %} 
						{% %}                  
						%}
						{%? (#FILTRO:@f_hasta!='') 
							{% AND REQ.f_req <={#FILTRO:@f_hasta} %} 
							{% %} 
						%}
					ORDER BY c_req ASC, f_req ASC	                               
  		')/ROWS/ROW
